import { useEffect, useRef, useState } from "react";

/* ══════════════════════════════════════════════════════════════════════
   GHOST PROJECT AI — MVP
   Identidade visual: fibra de carbono + dourado #d4af37
   Fundo: imagem de branding embedada (sem depender de arquivo público)
   Relógio: Watch.glb na pasta public/
══════════════════════════════════════════════════════════════════════ */

/* Imagem de branding — fundo + logo — embedada em base64 */
const BRAND_IMG = "data:image/jpeg;base64,";

/* Cores extraídas da imagem */
const GOLD    = "#d4af37";
const GOLD2   = "#c9953a";
const SILVER  = "#a8b4bc";
const WHITE   = "#f0ede8";

const CSS = [
  "@import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;0,600;1,300&family=Montserrat:wght@200;300;400;500;600;700&display=swap');",
  "*, *::before, *::after { box-sizing:border-box; margin:0; padding:0; }",
  ":root { --gold:#d4af37; --gold2:#c9953a; --silver:#a8b4bc; --wh:#f0ede8; --gn:#4ade80; }",
  /* Fundo global = imagem de branding */
  "html, body, #root {",
  "  width:100%; height:100%; overflow:hidden;",
  "  font-family:'Montserrat',sans-serif;",
  "  -webkit-tap-highlight-color:transparent; user-select:none;",
  "}",
  "@keyframes fadeIn  { from{opacity:0} to{opacity:1} }",
  "@keyframes fadeUp  { from{opacity:0;transform:translateY(18px)} to{opacity:1;transform:translateY(0)} }",
  "@keyframes shimmer { 0%{background-position:-200% center} 100%{background-position:200% center} }",
  "@keyframes pulse   { 0%,100%{opacity:.4;transform:scale(1)} 50%{opacity:1;transform:scale(1.2)} }",
  "@keyframes spin    { from{transform:rotate(0deg)} to{transform:rotate(360deg)} }",
  "@keyframes glow    { 0%,100%{box-shadow:0 0 18px rgba(212,175,55,.35)} 50%{box-shadow:0 0 45px rgba(212,175,55,.85),0 0 80px rgba(212,175,55,.2)} }",
  "@keyframes scan    { 0%{top:0%} 100%{top:100%} }",
  "@keyframes pop     { 0%{opacity:0;transform:scale(.4)} 80%{transform:scale(1.06)} 100%{opacity:1;transform:scale(1)} }",
  "@keyframes arBadge { 0%,100%{box-shadow:0 0 8px rgba(74,222,128,.3)} 50%{box-shadow:0 0 18px rgba(74,222,128,.8)} }",
  "@keyframes logoFloat { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-6px)} }",
].join("\n");

/* ── Fundo compartilhado (usado em Splash + Home) ── */
const BG_STYLE = {
  backgroundImage: "url(" + BRAND_IMG + ")",
  backgroundSize: "cover",
  backgroundPosition: "center top",
  backgroundRepeat: "no-repeat",
};

/* ── Glass card — glassmorphism sobre a fibra de carbono ── */
const glass = (extra) => ({
  background: "rgba(10,14,20,.55)",
  backdropFilter: "blur(14px)",
  WebkitBackdropFilter: "blur(14px)",
  border: "1px solid rgba(212,175,55,.22)",
  ...extra,
});

/* ══ Splash ══════════════════════════════════════════════════════════ */
function Splash({ onDone }) {
  const [show, setShow] = useState(false);
  const [out,  setOut]  = useState(false);
  useEffect(() => {
    const t1 = setTimeout(() => setShow(true), 300);
    const t2 = setTimeout(() => setOut(true),  2500);
    const t3 = setTimeout(onDone,              3100);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, []);

  return (
    <div style={{
      position:"fixed", inset:0, zIndex:200,
      ...BG_STYLE,
      display:"flex", flexDirection:"column",
      alignItems:"center", justifyContent:"center",
      opacity: out ? 0 : 1, transition:"opacity .6s ease",
    }}>
      {/* Overlay escuro para contrastar */}
      <div style={{position:"absolute",inset:0,background:"rgba(4,6,10,.45)",pointerEvents:"none"}}/>

      {/* Logo: a própria imagem de branding recortada no centro */}
      <div style={{
        position:"relative", zIndex:1,
        opacity: show ? 1 : 0,
        transform: show ? "translateY(0) scale(1)" : "translateY(20px) scale(.92)",
        transition:"all .8s cubic-bezier(.16,1,.3,1)",
        animation: show ? "logoFloat 4s ease-in-out infinite" : "none",
        textAlign:"center",
      }}>
        {/* Mostrar só a parte central da imagem (logo) */}
        <div style={{
          width: "min(58vw, 220px)",
          height: "min(58vw, 220px)",
          borderRadius:"50%",
          overflow:"hidden",
          margin:"0 auto",
          boxShadow:"0 0 40px rgba(212,175,55,.5), 0 0 80px rgba(212,175,55,.2)",
          border:"1px solid rgba(212,175,55,.3)",
        }}>
          <img
            src={BRAND_IMG}
            alt="Ghost Project AI"
            style={{
              width:"170%",
              marginLeft:"-35%",
              marginTop:"-5%",
              mixBlendMode:"lighten",
            }}
          />
        </div>

        <p style={{
          fontFamily:"'Montserrat',sans-serif",
          fontSize:9, letterSpacing:".55em", textTransform:"uppercase",
          color:"rgba(212,175,55,.7)", fontWeight:400,
          marginTop:18,
          opacity: show ? 1 : 0, transition:"opacity .8s ease .5s",
        }}>
          Luxury · Augmented Reality
        </p>
      </div>

      {/* Barra de carregamento */}
      <div style={{
        position:"absolute", bottom:55,
        width:110, height:1,
        background:"rgba(212,175,55,.18)",
        zIndex:1,
      }}>
        <div style={{
          height:"100%",
          background:"linear-gradient(90deg,transparent,var(--gold),transparent)",
          backgroundSize:"200% 100%",
          animation:"shimmer 1.3s linear infinite",
        }}/>
      </div>
    </div>
  );
}

/* ══ Home ════════════════════════════════════════════════════════════ */
function Home({ onStart, cam, setCam }) {
  const [press, setPress] = useState(false);

  return (
    <div style={{
      position:"fixed", inset:0,
      ...BG_STYLE,
      display:"flex", flexDirection:"column",
      alignItems:"center", justifyContent:"flex-start",
      paddingTop:"max(env(safe-area-inset-top,0px),48px)",
      paddingBottom:32,
      paddingLeft:22, paddingRight:22,
      animation:"fadeIn .6s ease",
      overflowY:"auto",
    }}>
      {/* Overlay escuro */}
      <div style={{position:"fixed",inset:0,background:"rgba(4,6,10,.52)",pointerEvents:"none"}}/>

      <div style={{position:"relative",zIndex:1,width:"100%",maxWidth:380,
        display:"flex",flexDirection:"column",alignItems:"center",gap:0}}>

        {/* LOGO — imagem recortada em círculo */}
        <div style={{
          width:"min(46vw,175px)", height:"min(46vw,175px)",
          borderRadius:"50%", overflow:"hidden",
          boxShadow:"0 0 32px rgba(212,175,55,.5), 0 0 64px rgba(212,175,55,.15)",
          border:"1px solid rgba(212,175,55,.28)",
          animation:"logoFloat 4s ease-in-out infinite",
          marginBottom:16,
          flexShrink:0,
        }}>
          <img
            src={BRAND_IMG}
            alt="Ghost Project AI"
            style={{
              width:"170%",
              marginLeft:"-35%",
              marginTop:"-5%",
              mixBlendMode:"lighten",
            }}
          />
        </div>

        {/* Nome do projeto */}
        <p style={{
          fontFamily:"'Montserrat',sans-serif",
          fontSize:10, letterSpacing:".48em", textTransform:"uppercase",
          color:"rgba(212,175,55,.65)", fontWeight:400,
          marginBottom:20,
          animation:"fadeUp .7s ease .1s both",
        }}>Ghost Project AI</p>

        {/* Headline */}
        <h1 style={{
          fontFamily:"'Cormorant Garamond',serif",
          fontSize:"clamp(30px,7.5vw,44px)", fontWeight:300,
          lineHeight:1.1, textAlign:"center",
          color:"var(--wh)",
          animation:"fadeUp .7s ease .15s both",
          marginBottom:10,
        }}>
          Try Before
          <br/>
          <span style={{
            background:"linear-gradient(135deg, #d4af37 0%, #f0d060 50%, #d4af37 100%)",
            backgroundSize:"200% auto",
            WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent",
            animation:"shimmer 3s linear infinite",
          }}>You Buy</span>
        </h1>

        {/* Subtítulo */}
        <p style={{
          fontSize:12, fontWeight:300, color:"rgba(168,180,192,.8)",
          lineHeight:1.75, maxWidth:265, textAlign:"center",
          letterSpacing:".03em",
          animation:"fadeUp .7s ease .22s both",
          marginBottom:24,
        }}>
          Visualize produtos em escala real através da sua câmera.
          <br/>Tecnologia AR que elimina devoluções.
        </p>

        {/* Seletor câmera — glassmorphism */}
        <div style={{
          ...glass({ borderRadius:13, padding:4 }),
          display:"flex", width:"100%", maxWidth:315,
          animation:"fadeUp .7s ease .3s both",
          marginBottom:11,
        }}>
          {[
            {v:"environment", l:"📷  Câmera Traseira"},
            {v:"user",        l:"🤳  Câmera Frontal"},
          ].map(x => (
            <button key={x.v} onClick={()=>setCam(x.v)} style={{
              flex:1, padding:"10px 4px", borderRadius:10,
              border:"none", cursor:"pointer",
              fontSize:11, fontWeight:500, letterSpacing:".04em",
              fontFamily:"'Montserrat',sans-serif", transition:"all .22s ease",
              background: cam===x.v
                ? "linear-gradient(135deg,#d4af37,#a07820)"
                : "transparent",
              color: cam===x.v ? "#07090D" : "rgba(168,180,192,.8)",
            }}>{x.l}</button>
          ))}
        </div>

        {/* Botão iniciar — dourado premium */}
        <button
          onClick={onStart}
          onPointerDown={()=>setPress(true)}
          onPointerUp={()=>setPress(false)}
          onPointerLeave={()=>setPress(false)}
          style={{
            position:"relative", overflow:"hidden",
            width:"100%", maxWidth:315, padding:"15px 24px",
            borderRadius:14,
            border:"1px solid rgba(212,175,55,.5)",
            cursor:"pointer",
            background:"linear-gradient(135deg,#d4af37 0%,#a07820 50%,#d4af37 100%)",
            backgroundSize:"200% auto",
            transform: press ? "scale(.97)" : "scale(1)",
            transition:"transform .13s ease",
            animation:"glow 2.5s ease-in-out infinite, fadeUp .7s ease .38s both, shimmer 3s linear infinite",
            fontFamily:"'Montserrat',sans-serif",
            marginBottom:22,
          }}>
          <span style={{
            display:"flex", alignItems:"center", justifyContent:"center", gap:9,
            fontSize:13, fontWeight:700, letterSpacing:".16em",
            color:"#07090D", textTransform:"uppercase",
          }}>
            <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <circle cx="12" cy="12" r="3"/>
              <path d="M3 9V6a2 2 0 012-2h3M3 15v3a2 2 0 002 2h3M15 3h3a2 2 0 012 2v3M15 21h3a2 2 0 002-2v-3"/>
            </svg>
            Iniciar Scanner AR
          </span>
          {/* Shimmer de brilho */}
          <div style={{
            position:"absolute", inset:0,
            background:"linear-gradient(90deg,transparent,rgba(255,255,255,.18),transparent)",
            backgroundSize:"200% 100%", animation:"shimmer 2s linear infinite",
            pointerEvents:"none",
          }}/>
        </button>

        <p style={{
          fontSize:8, color:"rgba(212,175,55,.28)",
          letterSpacing:".18em", textTransform:"uppercase",
          fontWeight:300, textAlign:"center",
          animation:"fadeUp .7s ease .44s both",
        }}>Ghost Project AI — Powered by WebXR</p>
      </div>
    </div>
  );
}

/* ══ AR Loading ══════════════════════════════════════════════════════ */
function ARLoading({ pct }) {
  const msgs = ["Iniciando câmera...","Carregando modelo 3D...","Preparando AR...","Quase pronto..."];
  return (
    <div style={{
      position:"fixed", inset:0, zIndex:80,
      background:"rgba(4,6,10,.97)", backdropFilter:"blur(20px)",
      display:"flex", flexDirection:"column",
      alignItems:"center", justifyContent:"center", gap:20,
      animation:"fadeIn .3s ease",
    }}>
      <div style={{position:"relative",width:64,height:64}}>
        <div style={{position:"absolute",inset:0,borderRadius:"50%",border:"2px solid transparent",
          borderTopColor:"var(--gold)",borderRightColor:"var(--gold)",animation:"spin .85s linear infinite"}}/>
        <div style={{position:"absolute",inset:9,borderRadius:"50%",border:"1px solid transparent",
          borderBottomColor:"rgba(212,175,55,.4)",animation:"spin 1.5s linear infinite reverse"}}/>
        <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",
          justifyContent:"center",fontSize:22}}>⌚</div>
      </div>
      <div style={{textAlign:"center"}}>
        <div style={{fontFamily:"'Cormorant Garamond',serif",fontSize:18,fontWeight:300,
          color:"var(--wh)",letterSpacing:".05em",marginBottom:5}}>
          Carregando modelo 3D
        </div>
        <div style={{fontSize:10,color:"var(--silver)",letterSpacing:".13em"}}>
          {msgs[Math.min(Math.floor(pct/25),3)]}
        </div>
      </div>
      <div style={{width:160,height:2,background:"rgba(255,255,255,.07)",borderRadius:2}}>
        <div style={{height:"100%",borderRadius:2,
          background:"linear-gradient(90deg,var(--gold),#f0d060)",
          width:pct+"%",transition:"width .2s ease",
          boxShadow:"0 0 10px rgba(212,175,55,.7)"}}/>
      </div>
    </div>
  );
}

/* ══ AR View ═════════════════════════════════════════════════════════ */
function ARView({ cam, onBack }) {
  const canvasRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [pct,     setPct]     = useState(0);
  const [ready,   setReady]   = useState(false);
  const [error,   setError]   = useState("");
  const R = useRef({});

  useEffect(() => {
    let raf, stream;
    const refs = R.current;

    const tick = setInterval(() => {
      setPct(p => { if(p>=78){clearInterval(tick);return p;} return p+Math.random()*12; });
    }, 180);

    function loadScript(src) {
      return new Promise((res,rej) => {
        if(document.querySelector('script[src="'+src+'"]')){res();return;}
        const s=document.createElement("script");
        s.src=src; s.onload=res;
        s.onerror=()=>rej(new Error("Falha: "+src));
        document.head.appendChild(s);
      });
    }

    async function init() {
      try {
        await loadScript("https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js");
        await loadScript("https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/loaders/GLTFLoader.js");
        const T = window.THREE;

        /* Câmera */
        stream = await navigator.mediaDevices.getUserMedia({
          video:{facingMode:cam,width:{ideal:1920},height:{ideal:1080}},audio:false,
        });
        const vid=document.createElement("video");
        vid.srcObject=stream; vid.playsInline=true; vid.muted=true;
        await new Promise(r=>{vid.onloadedmetadata=r;});
        await vid.play();

        /* Renderer */
        const renderer=new T.WebGLRenderer({
          canvas:canvasRef.current,alpha:true,antialias:true,
          powerPreference:"high-performance",
        });
        renderer.setSize(window.innerWidth,window.innerHeight);
        renderer.setPixelRatio(Math.min(window.devicePixelRatio,2));
        renderer.shadowMap.enabled=true;
        renderer.shadowMap.type=T.PCFSoftShadowMap;
        renderer.toneMapping=T.ACESFilmicToneMapping;
        renderer.toneMappingExposure=1.8;

        /* Cena com fundo de vídeo */
        const scene=new T.Scene();
        const vtex=new T.VideoTexture(vid);
        vtex.minFilter=T.LinearFilter;
        scene.background=vtex;

        const cam3=new T.PerspectiveCamera(50,window.innerWidth/window.innerHeight,0.01,100);
        cam3.position.set(0,0,2.8);
        refs.cam3=cam3;

        /* Iluminação premium */
        scene.add(new T.AmbientLight(0xffffff,0.4));
        const kL=new T.DirectionalLight(0xfff6e8,3.5);
        kL.position.set(-2,5,3);kL.castShadow=true;scene.add(kL);
        const fL=new T.DirectionalLight(0xd8eaff,0.6);
        fL.position.set(4,1,2);scene.add(fL);
        const rL=new T.DirectionalLight(0xffffff,1.2);
        rL.position.set(1,-2,-4);scene.add(rL);refs.rL=rL;
        const sG=new T.SpotLight(0xd4af37,5,9,Math.PI/3.5,0.25,1);
        sG.position.set(1,3,2);scene.add(sG);refs.sG=sG;
        const dL=new T.PointLight(0xffffff,2.5,3);
        dL.position.set(.3,.3,1.2);scene.add(dL);refs.dL=dL;

        /* Carregar modelo */
        setPct(80);
        const loader=new T.GLTFLoader();

        function tryLoad(path,ok,fail){
          loader.load(path,ok,
            xhr=>{if(xhr.lengthComputable)setPct(Math.max(80,Math.round(xhr.loaded/xhr.total*100)));},
            ()=>fail()
          );
        }

        function onModel(gltf){
          const model=gltf.scene;
          const box=new T.Box3().setFromObject(model);
          const size=new T.Vector3(); box.getSize(size);
          const center=new T.Vector3(); box.getCenter(center);
          model.position.sub(center);
          const maxDim=Math.max(size.x,size.y,size.z);
          model.scale.setScalar(0.32/maxDim);
          model.traverse(c=>{if(c.isMesh){c.castShadow=true;c.receiveShadow=true;}});
          const wg=new T.Group();
          wg.add(model);scene.add(wg);refs.wg=wg;
          wg.position.set(0,-0.02,0);
          wg.rotation.x=-0.12;
          setPct(100);
          setTimeout(()=>{setLoading(false);setReady(true);},280);

          const t0=Date.now();
          function loop(){
            raf=requestAnimationFrame(loop);
            const t=(Date.now()-t0)/1000;
            wg.rotation.y=Math.sin(t*.18)*.38;
            wg.rotation.x=-0.12+Math.sin(t*.11)*.05;
            wg.position.y=-0.02+Math.sin(t*.9)*.022;
            refs.sG.position.set(Math.sin(t*.22)*2.2,2.5+Math.cos(t*.18)*.5,2.0);
            refs.sG.intensity=4+Math.sin(t*.6)*.8;
            refs.dL.position.set(Math.cos(t*.35)*.5,Math.sin(t*.35)*.5,1.2);
            refs.dL.intensity=2+Math.sin(t*.9)*.5;
            refs.rL.intensity=1+Math.sin(t*.4)*.25;
            renderer.render(scene,cam3);
          }
          loop();
        }

        /* Tenta Watch.glb, depois relogio.glb */
        tryLoad("/Watch.glb",onModel,()=>{
          tryLoad("/relogio.glb",onModel,()=>{
            setError("Coloque Watch.glb ou relogio.glb na pasta public/");
            setLoading(false);
          });
        });

        function onResize(){
          cam3.aspect=window.innerWidth/window.innerHeight;
          cam3.updateProjectionMatrix();
          renderer.setSize(window.innerWidth,window.innerHeight);
        }
        window.addEventListener("resize",onResize);refs.onResize=onResize;

        let ltx=0;
        function onTS(e){ltx=e.touches[0].clientX;}
        function onTM(e){if(refs.wg)refs.wg.rotation.y+=(e.touches[0].clientX-ltx)*.011;ltx=e.touches[0].clientX;}
        const cv=canvasRef.current;
        if(cv){cv.addEventListener("touchstart",onTS);cv.addEventListener("touchmove",onTM);refs.ts=onTS;refs.tm=onTM;}

      } catch(err){
        clearInterval(tick);
        setError(err.message||"Erro ao iniciar câmera");
        setLoading(false);
      }
    }
    init();
    return ()=>{
      cancelAnimationFrame(raf);
      stream?.getTracks().forEach(t=>t.stop());
      window.removeEventListener("resize",refs.onResize);
      const cv=canvasRef.current;
      if(cv){cv.removeEventListener("touchstart",refs.ts);cv.removeEventListener("touchmove",refs.tm);}
    };
  },[cam]);

  return (
    <div style={{position:"fixed",inset:0,background:"#000"}}>
      {loading && <ARLoading pct={pct}/>}
      <canvas ref={canvasRef} style={{width:"100%",height:"100%",display:"block",touchAction:"none"}}/>

      {!loading && !error && (
        <>
          {/* HUD Topo */}
          <div style={{
            position:"absolute",top:0,left:0,right:0,
            paddingTop:"max(env(safe-area-inset-top,0px),44px)",
            paddingBottom:12,paddingLeft:14,paddingRight:14,
            background:"linear-gradient(to bottom,rgba(4,6,10,.88),rgba(4,6,10,.3),transparent)",
            display:"flex",flexDirection:"column",alignItems:"center",gap:6,
          }}>
            <div style={{width:"100%",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <button onClick={onBack} style={{
                display:"flex",alignItems:"center",gap:5,
                padding:"6px 14px",borderRadius:100,
                background:"rgba(255,255,255,.07)",border:"1px solid rgba(255,255,255,.12)",
                color:WHITE,fontSize:11,fontWeight:500,cursor:"pointer",
                letterSpacing:".05em",backdropFilter:"blur(8px)",
                fontFamily:"'Montserrat',sans-serif",
              }}>← Voltar</button>

              {/* Badge AR ACTIVE */}
              <div style={{
                display:"flex",alignItems:"center",gap:7,
                padding:"7px 15px",borderRadius:100,
                background:"rgba(10,40,25,.9)",
                border:"1px solid rgba(74,222,128,.4)",
                backdropFilter:"blur(10px)",
                animation:"arBadge 2s ease-in-out infinite",
              }}>
                <span style={{fontSize:10,fontWeight:700,color:"#4ade80",letterSpacing:".12em"}}>AR ACTIVE</span>
                <div style={{width:7,height:7,borderRadius:"50%",background:"#4ade80",
                  boxShadow:"0 0 8px rgba(74,222,128,.9)",animation:"pulse 1.5s ease-in-out infinite"}}/>
              </div>
            </div>

            {/* Título e specs — glass card */}
            <div style={{
              ...glass({borderRadius:10,padding:"8px 18px"}),
              textAlign:"center",marginTop:4,
            }}>
              <div style={{
                fontFamily:"'Montserrat',sans-serif",fontSize:15,fontWeight:700,
                color:WHITE,letterSpacing:".2em",
                textShadow:"0 0 18px rgba(212,175,55,.45)",
              }}>GHOST PROJECT</div>
              <div style={{fontSize:9,fontWeight:300,color:GOLD,
                letterSpacing:".3em",textTransform:"uppercase",marginTop:2}}>LUXURY AR</div>
              <div style={{fontSize:9,color:"rgba(240,237,232,.55)",
                letterSpacing:".08em",marginTop:5,lineHeight:1.5}}>
                44MM | Sapphire Crystal | 100M WR
              </div>
            </div>
          </div>

          {/* Cantos scanner */}
          <div style={{position:"absolute",inset:"18%",pointerEvents:"none"}}>
            <div style={{position:"absolute",top:0,left:0,width:22,height:22,
              borderTop:"1.5px solid "+GOLD,borderLeft:"1.5px solid "+GOLD,opacity:.75}}/>
            <div style={{position:"absolute",top:0,right:0,width:22,height:22,
              borderTop:"1.5px solid "+GOLD,borderRight:"1.5px solid "+GOLD,opacity:.75}}/>
            <div style={{position:"absolute",bottom:0,left:0,width:22,height:22,
              borderBottom:"1.5px solid "+GOLD,borderLeft:"1.5px solid "+GOLD,opacity:.75}}/>
            <div style={{position:"absolute",bottom:0,right:0,width:22,height:22,
              borderBottom:"1.5px solid "+GOLD,borderRight:"1.5px solid "+GOLD,opacity:.75}}/>
            {/* Grid decorativo */}
            <div style={{position:"absolute",left:0,right:0,top:"50%",height:1,
              background:"linear-gradient(90deg,rgba(212,175,55,.1),rgba(212,175,55,.35),rgba(212,175,55,.1))"}}/>
            <div style={{position:"absolute",top:0,bottom:0,left:"50%",width:1,
              background:"linear-gradient(180deg,rgba(212,175,55,.1),rgba(212,175,55,.35),rgba(212,175,55,.1))"}}/>
            {/* Scan line */}
            <div style={{position:"absolute",left:0,right:0,height:1,
              background:"linear-gradient(90deg,transparent,rgba(212,175,55,.85),transparent)",
              animation:"scan 2.5s linear infinite",
              boxShadow:"0 0 8px rgba(212,175,55,.6)"}}/>
          </div>

          {/* HUD Base */}
          <div style={{
            position:"absolute",bottom:0,left:0,right:0,
            paddingTop:14,paddingLeft:14,paddingRight:14,
            paddingBottom:"max(env(safe-area-inset-bottom,0px),28px)",
            background:"linear-gradient(to top,rgba(4,6,10,.9),rgba(4,6,10,.3),transparent)",
            display:"flex",flexDirection:"column",alignItems:"center",gap:8,
          }}>
            {/* Botão TRY-ON LIVE */}
            <button style={{
              position:"relative",overflow:"hidden",
              width:"100%",maxWidth:290,padding:"14px 24px",
              borderRadius:13,border:"1px solid rgba(212,175,55,.5)",
              cursor:"pointer",
              background:"linear-gradient(135deg,#d4af37 0%,#a07820 50%,#d4af37 100%)",
              backgroundSize:"200% auto",
              animation:"glow 2.5s ease-in-out infinite",
              fontFamily:"'Montserrat',sans-serif",
            }}>
              <span style={{fontSize:13,fontWeight:700,letterSpacing:".2em",
                color:"#07090D",textTransform:"uppercase"}}>
                TRY-ON LIVE
              </span>
              <div style={{position:"absolute",inset:0,
                background:"linear-gradient(90deg,transparent,rgba(255,255,255,.16),transparent)",
                backgroundSize:"200% 100%",animation:"shimmer 2s linear infinite",
                pointerEvents:"none"}}/>
            </button>

            <p style={{fontSize:8,color:"rgba(212,175,55,.35)",
              letterSpacing:".13em",textTransform:"uppercase",
              fontWeight:300,textAlign:"center"}}>
              Arraste para girar · Ghost Project AI
            </p>
          </div>
        </>
      )}

      {/* Erro */}
      {error && !loading && (
        <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",
          alignItems:"center",justifyContent:"center",gap:18,padding:28,
          background:"rgba(4,6,10,.98)"}}>
          <div style={{fontSize:34}}>📷</div>
          <div style={{fontFamily:"'Cormorant Garamond',serif",fontSize:20,
            color:WHITE,textAlign:"center"}}>Erro no Scanner AR</div>
          <p style={{fontSize:12,color:SILVER,textAlign:"center",
            lineHeight:1.75,maxWidth:260}}>{error}</p>
          <button onClick={onBack} style={{padding:"10px 24px",borderRadius:10,
            border:"1px solid rgba(212,175,55,.4)",background:"transparent",
            color:GOLD,cursor:"pointer",fontFamily:"'Montserrat',sans-serif",
            letterSpacing:".1em",fontSize:11}}>← Voltar</button>
        </div>
      )}
    </div>
  );
}

/* ══ Root ════════════════════════════════════════════════════════════ */
export default function App() {
  const [screen, setScreen] = useState("splash");
  const [cam,    setCam]    = useState("environment");
  return (
    <>
      <style>{CSS}</style>
      {screen==="splash" && <Splash onDone={()=>setScreen("home")}/>}
      {screen==="home"   && <Home   onStart={()=>setScreen("ar")} cam={cam} setCam={setCam}/>}
      {screen==="ar"     && <ARView cam={cam} onBack={()=>setScreen("home")}/>}
    </>
  );
}
